from decimal import Decimal, InvalidOperation, ROUND_HALF_EVEN

def parse_pipeline(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {"edad": None, "monto": None}
    errors = []
    et = edad_txt.strip()
    if et == "":
        errors.append("edad: vacío")
    else:
        try:
            clean["edad"] = int(et)
        except ValueError:
            errors.append(f"edad: no entero {edad_txt!r}")
    mt = monto_txt.strip()
    if mt == "":
        errors.append("monto: vacío")
    else:
        try:
            clean["monto"] = Decimal(mt).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        except (InvalidOperation, ValueError):
            errors.append(f"monto: no Decimal {monto_txt!r}")
    return {"raw": raw, "clean": clean, "errors": errors}

print(parse_pipeline(" 34 ", "150.5"))
print(parse_pipeline("x", "20.00"))

