def safe_int(campo: str, valor):
    if valor is None:
        return (True, None, None)
    texto = str(valor).strip()
    if texto == "":
        return (False, None, f"{campo}: vacío")
    try:
        return (True, int(texto), None)
    except ValueError:
        return (False, None, f"{campo}: no entero {valor!r}")

def parse_client(nombres, apellido_paterno, apellido_materno, contacto, direccion, edad=None):
    errors = []
    out = {
        "nombres_raw": nombres,
        "apellido_paterno_raw": apellido_paterno,
        "apellido_materno_raw": apellido_materno,
        "contacto_raw": contacto,
        "direccion_raw": direccion,
        "nombres": nombres.strip() or None,
        "apellido_paterno": apellido_paterno.strip() or None,
        "apellido_materno": apellido_materno.strip() or None,
        "contacto": contacto.strip() or None,
        "direccion": direccion.strip() or None,
        "edad": None,
        "errors": errors,
    }
    if out["nombres"] is None:
        errors.append("nombres: vacío")
    ok, n, err = safe_int("edad", edad)
    if not ok:
        errors.append(err)
    else:
        out["edad"] = n
    return out

t1 = parse_client("  Ana  ", "Ramos", "Ñahui", "999", "Lima", "34")
assert t1["apellido_materno"] == "Ñahui" and not t1["errors"]
t2 = parse_client("  ", "Ramos", "X", "1", "Cusco", "20")
assert any("nombres" in e for e in t2["errors"])
t3 = parse_client("Luis", "Perez", "Diaz", "2", "AQP", "abc")
assert any("edad" in e for e in t3["errors"])
print("suite OK", t1["nombres"], t2["errors"], t3["errors"])
